const res = $input.first().json;
const rawText = res.content[0].text;

let scoreData;
try {
  scoreData = JSON.parse(rawText);
} catch(e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) scoreData = JSON.parse(match[0]);
  else throw new Error('Could not parse: ' + rawText);
}

const orig = $('Slack Trigger — #mike-ideas').first().json;

return [{
  json: {
    ...scoreData,
    original_text: orig.event.text,
    channel: orig.event.channel,
    thread_ts: orig.event.ts,
    submitted_by: orig.event.user
  }
}];

